LIBWK2GTKPDF_1.0 {
    global:
        # Only export the names you actually want the world to see
        extern "C++" {
            phtml::PDFprinter::*;
            phtml::html_tree::*;
            phtml::encode_image::*;
            icGTK::*;
            iclog::*;
            "wkJlog";

            # Global namespace functions that aren't class members
            phtml::process_nodes*;
        };
        # If you have any raw C functions like PDF_FreeAnchors
        PDF_FreeAnchors;
        wk2gtkpdf_version;
        LOG_LEVEL;
        LOG_IGNORE;
        PDF_FreeBlob;
        PDF_FreeHTML;
    local:
        # Hide everything else, including PoDoFo and std::regex leaks
        *;
};
